module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
parameter size = 4;
reg [3:0] reg [0:3];
wire [3:0] partial_product [0:3];
wire [7:0] adder_out;
wire [3:0] a_ext, b_ext;
assign a_ext = {4'b0, mul_a};
assign b_ext = {4'b0, mul_b};
genvar i;
generate
    for(i = 0; i < size; i = i + 1) begin : gen_partial_product
        assign partial_product[i] = (b_ext[i] == 1'b1) ? a_ext << i : 'd0;
    end
endgenerate
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        for(i = 0; i < size; i = i + 1)
            reg[i] <= 'd0;
    end
    else begin
        for(i = 0; i < size; i = i + 1)
            reg[i] <= reg[i] + partial_product[i];
    end
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n)
        mul_out <= 'd0;
    else
        mul_out <= reg[0] + reg[1] + reg[2] + reg[3];
end
endmodule
